1	type Item = { type: string };
2	type Step = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	type Result = { premium: number };
5	
6	const PROCESSING_FEE = 5;
7	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
8	const BASE_PREMIUM: Record<string, number> = { sword: 100, amulet: 60, staff: 80 };
9	
10	const premiumForItem = (item: Item): number => {
11	  const base = BASE_PREMIUM[item.type];
12	  return base + base * FIRST_INSURANCE_SURCHARGE_RATE;
13	};
14	
15	const sum = (numbers: number[]): number => numbers.reduce((a, b) => a + b, 0);
16	
17	export const runScenario = (scenario: Scenario): { results: Result[] } => {
18	  const results = scenario.steps.map((step) => {
19	    const total = sum(step.items.map(premiumForItem)) + PROCESSING_FEE;
20	    return { premium: Math.ceil(total) };
21	  });
22	  return { results };
23	};
